import os
import boto3
from tensorflow.keras.models import load_model

s3 = boto3.client('s3')

def get_latest_model_version(bucket, prefix):
    """Get the latest model version from S3"""
    models = s3.list_objects_v2(Bucket=bucket, Prefix=prefix)
    versions = []
    
    for obj in models.get('Contents', []):
        versions.append(int(obj['Key'].split('-')[-1].replace('.h5', '')))
        
    return max(versions)

def load_model_from_s3(bucket, model_path):
    """Load the latest model from S3"""
    prefix = model_path + '-v-'
    version = get_latest_model_version(bucket, prefix)
    
    model_path_with_version = f'{model_path}-v-{version}.h5'
    s3.download_file(Bucket=bucket, Key=model_path_with_version, Filename='latest.h5')
    
    return load_model('latest.h5')

if 'MODEL_PATH' not in os.environ:
    raise ValueError("MODEL_PATH environment variable is required")
  
bucket = 'your-bucket-name'
model_path = os.environ['MODEL_PATH']
model = load_model_from_s3(bucket, model_path)